#!/usr/bin/env node
// Temporary diagnostic — not part of the pipeline, deleted after use.
// Validation run #2 for the "and"-split rule. Same rule as round 1, with
// three changes only:
//   1. NEW: a trigger does not split unless the text before it already
//      contains a force-word (shall/must/may/should) -- FIRST_SIDE_NOT_A_DUTY.
//   2. DROP: the nested-clause guard is removed entirely.
//   3. FIX: control-group tagging is evaluated at the trigger location, not
//      by scanning the whole sentence.
// Everything else (trigger definition, "will" excluded as a trigger
// force-word, multiple splits per sentence, actor inheritance via pendingForce,
// the fail-safe) is unchanged from round 1. Raw output only -- no design, no
// fixes, no pipeline changes.

import { readFileSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { fetchBillTextData } from "../api/wa-bill-text.js";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DATA_DIR = path.join(__dirname, "../data/wa");
const BIENNIUM = "2025-26";
const SAMPLE_SIZE = 200;
const OUTPUT_FILE = path.join(__dirname, "../tmp-validation-run2-results.txt");
const ROUND1_TOTAL_SPLITS = 220;

const BILL_INDEX = JSON.parse(readFileSync(path.join(DATA_DIR, "bill-index.json"), "utf8"));
const TEST_BILLS_CONFIG = JSON.parse(readFileSync(path.join(DATA_DIR, "test-bills.json"), "utf8"));
const excludedNumbers = new Set([...TEST_BILLS_CONFIG.sentinels, ...(TEST_BILLS_CONFIG.noDocumentBills || [])]);
const pool = [...new Set(
  BILL_INDEX.map(b => Number(b.bill_number))
    .filter(n => !excludedNumbers.has(n))
    .filter(n => !(n >= 4000 && n <= 4999))
    .filter(n => !(n >= 8000 && n <= 8999))
)].sort((a, b) => a - b);

const step = Math.max(1, Math.floor(pool.length / SAMPLE_SIZE));
const batch = [];
for (let i = 0; i < pool.length; i += step) batch.push(pool[i]);

function splitSentences(text) {
  return text
    .split(/(?<=[.!?;])\s+(?=[A-Z("])/)
    .map((s) => s.trim())
    .filter((s) => s.length > 15);
}

const singleLine = (s) => s.replace(/\s+/g, " ").trim();

